    values
      ('queen_seen_yes', 'Dronning observert', 'Dronningen er sett i inspeksjonen og bekrefter aktiv dronning akkurat na.', 'En observert dronning gir tryggere vurdering av kuben i samme inspeksjon. Funnet bor ses sammen med egg, larver, gemytt og generell utvikling.', '["Rolig gjennomgang ga god oversikt", "Dronningen oppholdt seg pa synlig tavle", "Kuben lot seg inspisere uten stor uro"]', '["Noter farge og argang hvis kjent", "Sammenhold funnet med egg og larver", "Bruk observasjonen som referanse ved neste inspeksjon"]', 'low', 'beginner', 'all', '["inspection", "dronning", "observasjon"]', null),
      ('queen_seen_no', 'Dronning ikke observert', 'Dronningen ble ikke sett i inspeksjonen, men det betyr ikke automatisk at hun mangler.', 'Mange friske kuber inspiseres uten at dronningen blir sett. Vurder alltid manglende observasjon opp mot egg, larver, ro i kuben og om inspeksjonen var rask eller forstyrrende.', '["Dronningen ble oversett", "Lysforhold eller tempo gjorde henne vanskelig a finne", "Dronningen oppholdt seg pa en tavle som ikke ble lest godt nok"]', '["Se etter ferske egg og ung larve", "Unnga store tiltak bare fordi dronningen ikke ble sett", "Planlegg ny kontroll hvis flere tegn peker mot dronningproblem"]', 'medium', 'beginner', 'all', '["inspection", "dronning", "usikkerhet"]', 3),
      ('queen_unknown', 'Usikker dronningsituasjon', 'Egg er sett, men dronningen er ikke observert. Dronningen kan vaere oversett eller nylig ha lagt egg.', 'Nar ferske egg finnes uten at dronningen er sett, er kuben ofte fortsatt dronningrett. Likevel bor situasjonen bekreftes pa nytt dersom andre tegn er uklare eller utviklingen virker ujevn.', '["Dronningen ble oversett under inspeksjonen", "Eggene er nylig lagt av aktiv dronning", "Kuben var urolig eller vanskelig a lese"]', '["Kontroller pa nytt innen fa dager", "Se etter jevn egglegging og ung larve", "Vurder gemytt og kubens ro for du konkluderer"]', 'medium', 'beginner', 'all', '["inspection", "dronning", "egg", "regel"]', 3),
      ('queen_missing', 'Mistanke om manglende dronning', 'Nar verken dronning eller ferske egg blir funnet, ma dronningsituasjonen avklares raskt.', 'Manglende dronning ma alltid vurderes opp mot larver, yngel, dronningceller og kubens oppforsel. Tidlig oppfolging kan avgjore om kuben kan reddes eller ma slas sammen.', '["Dronningen er tapt", "Dronningen svikter og legger ikke egg", "Stille omskifting eller nylig dronningbytte er i gang"]', '["Kontroller tavlene pa nytt for ferske egg og dronningceller", "Vurder tiltak forst nar situasjonen er bekreftet", "Planlegg ny inspeksjon raskt og noter alle tegn"]', 'high', 'intermediate', 'all', '["inspection", "dronning", "problem"]', 3),
      ('queen_replaced', 'Dronning er byttet eller satt inn', 'Ny dronning betyr at kuben ma folges opp for a bekrefte aksept og stabil egglegging.', 'Et dronningbytte er ikke ferdig ved innsetting. Kubeutviklingen ma folges opp til ny dronning er akseptert og legger jevnt.', '["Tidligere dronning var svak eller borte", "Birokteren onsket bedre gemytt eller utvikling", "Kuben hadde behov for nytt genetisk materiale"]', '["Kontroller om ny dronning er akseptert", "Se etter ferske egg ved neste inspeksjon", "Unnga unodvendig forstyrrelse rett etter bytte"]', 'medium', 'intermediate', 'summer', '["inspection", "dronning", "tiltak"]', 7),
      ('eggs_seen_yes', 'Egg observert', 'Ferske egg er et sterkt tegn pa aktiv eller nylig aktiv dronning.', 'Nar egg er registrert, gir det viktig biologisk informasjon om kubens utvikling. Egg bor vurderes sammen med mengde larver, yngel og generelt gemytt.', '["Dronningen har lagt egg nylig", "Kuben utvikler seg normalt", "Inspeksjonen ble gjort pa et tidspunkt der egg var lette a se"]', '["Noter om eggmengden virker jevn eller ujevn", "Se etter larver i tilsvarende utvikling", "Bruk funnet som kontrollpunkt ved neste inspeksjon"]', 'low', 'beginner', 'all', '["inspection", "egg", "observasjon"]', null),
      ('eggs_seen_no', 'Egg ikke observert', 'Nar egg ikke er sett, bor funnet vurderes opp mot larver, dronning og sesong.', 'Manglende egg kan vaere normalt ved spesielle situasjoner, men kan ogsa varsle dronningsvikt eller nylig avbrudd i egglegging. Tolking uten biologisk sammenheng gir lett feil konklusjon.', '["Dronningen har pause i egglegging", "Dronningen er svak eller borte", "Egg ble oversett i darlig lys eller hurtig inspeksjon"]', '["Se etter ung larve og dronningceller", "Vurder om kuben trenger rask ny kontroll", "Tolk funnet sammen med sesong og bistyrke"]', 'medium', 'beginner', 'all', '["inspection", "egg", "oppfolging"]', 3),
      ('egg_none', 'Ingen egg registrert', 'Ingen egg er registrert i inspeksjonen.', 'Fravaer av egg ma vurderes sammen med om dronningen er sett, om larver finnes og om kuben er i en overgangsfase.', '["Dronningen er borte eller svikter", "Nylig dronningbytte eller stille omskifting", "Eggleggingen er kortvarig avbrutt"]', '["Kontroller pa nytt for ferske egg", "Se etter dronningceller og ung larve", "Folges opp raskt hvis andre tegn er negative"]', 'medium', 'beginner', 'all', '["inspection", "egg", "mengde"]', 3),
      ('egg_lite', 'Lite egg', 'Lite egg kan vaere normalt i svakere kuber eller ved overgang i utviklingen.', 'Lav eggmengde bor ses sammen med dronningens kvalitet, bistyrke, trekkforhold og sesong.', '["Svak eller ung dronning", "Tidlig eller sen sesong", "Kuben bygger seg opp etter pause eller inngrep"]', '["Sammenlign med larver og yngel", "Folges opp hvis utviklingen blir staende lav", "Vurder kubens totale styrke for tiltak"]', 'low', 'beginner', 'all', '["inspection", "egg", "mengde"]', 7),
      ('egg_normal', 'Normal egglegging', 'Normal eggmengde tyder pa jevn og forventet utvikling.', 'Normal egglegging er et godt tegn dersom larver og yngel folger samme bilde. Bruk dette som referanse for stabil drift.', '["Dronningen legger jevnt", "Kuben har tilstrekkelig plass og ressurser", "Utviklingen er biologisk balansert"]', '["Behold normal oppfolging", "Vurder plass og for mot videre vekst", "Sammenlign med neste inspeksjon"]', 'low', 'beginner', 'all', '["inspection", "egg", "mengde"]', null),
      ('egg_mye', 'Mye egg', 'Stor eggmengde tyder ofte pa sterk utvikling og aktiv dronning.', 'Mange egg er positivt dersom kuben samtidig har plass, for og tilstrekkelig arbeidsbier. Uten kapasitet kan sterk vekst gi svermetrykk.', '["Sterk og aktiv dronning", "God trekk og plass i kuben", "Rask varekspansjon eller sommerutvikling"]', '["Vurder plassbehov og skattekasse", "Sammenhold med bistyrke og svermetegn", "Folges opp tett i aktiv sesong"]', 'medium', 'beginner', 'all', '["inspection", "egg", "mengde"]', 3),
      ('larver_none', 'Ingen larver registrert', 'Ingen larver kan bety at eggleggingen har stoppet opp eller nylig endret seg.', 'Nar larver mangler, bor du alltid se dette sammen med egg, lukket yngel og dronningstatus for a forsta hvor i utviklingen kuben star.', '["Manglende eller svak egglegging", "Nylig brudd i yngelutviklingen", "Larvene ble oversett eller var for sma a se tydelig"]', '["Kontroller egg pa nytt", "Se etter forskjell mellom apen og lukket yngel", "Planlegg ny inspeksjon hvis bildet er ulogisk"]', 'medium', 'beginner', 'all', '["inspection", "larver", "mengde"]', 3),
      ('larver_lite', 'Lite larver', 'Lite larver kan passe med svak utvikling eller tidlig oppbygging.', 'Lav larvemengde er ikke alene et problem, men bor ses opp mot egg, yngel og kubens totale styrke.', '["Moderat eller lav egglegging", "Tidlig sesong eller liten kube", "Nylig inngrep som har bremset utviklingen"]', '["Sammenlign med egg og lukket yngel", "Vurder om utviklingen peker opp eller ned", "Folges opp ved vedvarende svak vekst"]', 'low', 'beginner', 'all', '["inspection", "larver", "mengde"]', 7),
      ('larver_normal', 'Normal mengde larver', 'Normal larvemengde tyder pa jevn overgang fra egg til yngel.', 'Nar larver ligger pa normalt nivaa sammen med egg og yngel, er kubens yngelflyt ofte stabil.', '["Jevn egglegging", "God stell av yngel", "Tilstrekkelig varme og arbeidsbier i kuben"]', '["Fortsett normal oppfolging", "Bruk funnet som referanse ved senere inspeksjoner", "Vurder plass og for etter sesong"]', 'low', 'beginner', 'all', '["inspection", "larver", "mengde"]', null),
      ('larver_mye', 'Mye larver', 'Stor larvemengde tyder pa sterk utvikling og god overgang fra egglegging.', 'Mange larver krever varme, nok arbeidsbier og god tilgang pa for. Hoy larvemengde bor ses sammen med plass og kommende behov i kuben.', '["Sterk dronning og god yngelpleie", "God trekk eller fortilgang", "Kuben er i rask vekst"]', '["Sjekk at kuben har kapasitet og plass", "Vurder skattekasse eller avlegger ved sterk utvikling", "Folg opp innen kort tid i aktiv sesong"]', 'medium', 'beginner', 'all', '["inspection", "larver", "mengde"]', 3),
      ('yngel_none', 'Ingen lukket yngel registrert', 'Manglende lukket yngel kan vaere normalt ved skifte i yngelbildet, men ma vurderes biologisk.', 'Ingen lukket yngel ma sammenholdes med egg og larver for a se om kuben er i normal overgang eller om utviklingen har stoppet.', '["Nylig oppstart i egglegging", "Brudd i yngelutviklingen", "Dronningproblem eller nylig inngrep"]', '["Vurder hele yngelbildet samlet", "Se etter ferske egg og larver", "Folg opp raskere hvis ogsa andre tegn er svake"]', 'medium', 'beginner', 'all', '["inspection", "yngel", "mengde"]', 3),
      ('yngel_lite', 'Lite lukket yngel', 'Lite lukket yngel kan passe med svak eller nylig endret utvikling.', 'Lav mengde lukket yngel betyr lav kommende klekking og kan gi svak bemanning hvis bildet ikke bedres.', '["Lav egglegging tidligere", "Nylig pause i yngelproduksjon", "Liten eller svekket kube"]', '["Sammenlign med egg og larver", "Vurder bistyrke og forreserver", "Folg opp dersom kuben ikke bygger seg opp"]', 'medium', 'beginner', 'all', '["inspection", "yngel", "mengde"]', 7),
      ('yngel_normal', 'Normal mengde lukket yngel', 'Normal lukket yngel betyr god kommende rekruttering av bier.', 'Nar lukket yngel ligger normalt, tyder det pa at kuben nylig har hatt jevn egglegging og at ny arbeidsstyrke er pa vei.', '["Jevn dronningaktivitet", "God yngelpleie", "Stabil kubeutvikling"]', '["Fortsett vanlig inspeksjonsrytme", "Bruk funnet som referanse for videre utvikling", "Sammenhold med bistyrke ved neste kontroll"]', 'low', 'beginner', 'all', '["inspection", "yngel", "mengde"]', null),
      ('yngel_mye', 'Mye lukket yngel', 'Mye lukket yngel varsler sterk kommende klekking og rask vekst.', 'Mye lukket yngel kan gi kraftig okning i bistyrke. Kubevolum, plass og for ma matche denne utviklingen.', '["Sterk egglegging over tid", "Gode trekkforhold", "Kuben er i ekspansjonsfase"]', '["Vurder ekstra plass og skattekasse", "Hold oye med svermetrang", "Folg opp tett i sterk sesong"]', 'medium', 'beginner', 'all', '["inspection", "yngel", "mengde"]', 3),
      ('droner_none', 'Ingen droner registrert', 'Ingen droner kan vaere normalt utenfor aktiv droneperiode.', 'Fravaer av droner ma vurderes etter sesong. I var og tidlig sommer kan det si noe om kubeutviklingen, mens senere eller tidlig i sesongen kan det vaere normalt.', '["Tidlig eller sen sesong", "Kuben prioriterer arbeiderbier", "Svak utvikling eller begrenset dronebygging"]', '["Tolk funnet ut fra arstid", "Sammenhold med kubestyrke og svermtegn", "Ingen tiltak trengs alene uten andre funn"]', 'low', 'beginner', 'all', '["inspection", "droner", "mengde"]', null),
      ('droner_lite', 'Lite droner', 'Lite droner er ofte normalt i kuber som ikke har sterkt sverm eller produksjonstrykk.', 'Lav droneandel er som regel uproblematisk, men kan gi ekstra kontekst sammen med bistyrke og eventuelle dronningproblemer.', '["Moderat utvikling", "Sesong eller vaer begrenser droneproduksjon", "Kuben prioriterer annet yngelarbeid"]', '["Bruk funnet som kontekst og ikke alene", "Vurder sammen med gemytt og dronningstatus", "Folg vanlig inspeksjonsrytme"]', 'low', 'beginner', 'all', '["inspection", "droner", "mengde"]', null),
      ('droner_normal', 'Normal mengde droner', 'Normal droneandel passer med vanlig sesongutvikling.', 'Et normalt dronenivaa gir liten grunn til tiltak alene, men er nyttig som biologisk referanse i sesongen.', '["Normal sesongutvikling", "Kuben har tilstrekkelig ressurser", "Dronning og bistyrke virker balansert"]', '["Fortsett normal oppfolging", "Bruk som referanse hvis kuben endrer seg senere", "Se dronebildet i sammenheng med svermetegn"]', 'low', 'beginner', 'all', '["inspection", "droner", "mengde"]', null),
      ('droner_mye', 'Mye droner', 'Stor droneandel kan tyde pa sterk sesongutvikling eller okt svermpress.', 'Hoy droneandel kan vaere normalt i aktiv sesong, men blir mer interessant dersom kuben ogsa er sterk, trang eller viser svermtegn.', '["Sterk sesongutvikling", "Kuben bygger mot sverming", "God ressursbase gir rom for droneproduksjon"]', '["Vurder plass og svermetegn", "Sammenhold med bistyrke og dronningceller", "Folg opp raskere ved tegn til trang kube"]', 'medium', 'beginner', 'spring', '["inspection", "droner", "mengde"]', 3),
      ('bistyrke_ukjent', 'Ukjent bistyrke', 'Rammer med yngel er ikke registrert, sa kapasitetsvurdering blir mer usikker.', 'Nar bistyrken er ukjent, bor Aurora vaere forsiktig med anbefalinger om skattekasse, avlegger og svermtiltak.', '["Manglende registrering", "Inspeksjonen var rask eller ufullstendig", "Rammene lot seg ikke telle presist"]', '["Registrer rammer med yngel neste gang", "Unnga bastante konklusjoner om kapasitet", "Bruk andre felt som stotte til vurderingen"]', 'low', 'beginner', 'all', '["inspection", "bistyrke", "kapasitet"]', null),
      ('bistyrke_1_2', 'Bistyrke 1 til 2 rammer', 'Svaert liten bistyrke betyr begrenset kapasitet og hoy sarbarhet.', 'Sma kuber trenger tett vurdering av for, dronningstatus og om veksten faktisk er pa vei opp.', '["Nylig avlegger", "Svak utvikling eller tap av bier", "Tidlig oppbygging eller nylig problem"]', '["Prioriter overlevelse og stabil utvikling", "Unnga tiltak som krever overskudd", "Folg opp raskt hvis andre funn ogsa er svake"]', 'high', 'beginner', 'all', '["inspection", "bistyrke", "kapasitet"]', 3),
      ('bistyrke_3_4', 'Bistyrke 3 til 4 rammer', 'Liten til moderat bistyrke krever fortsatt tett biologisk vurdering.', 'Kuben kan vokse godt videre, men har ofte begrenset buffer mot darlig vaer, roving og formangel.', '["Oppbygging pagar", "Liten eller middels kube", "Utviklingen er ikke fullt etablert enna"]', '["Folg utviklingen fra uke til uke", "Sjekk for og egglegging", "Vurder a stotte kuben heller enn a belaste den"]', 'medium', 'beginner', 'all', '["inspection", "bistyrke", "kapasitet"]', 7),
      ('bistyrke_5_6', 'Bistyrke 5 til 6 rammer', 'Middels bistyrke gir ofte god arbeidskapasitet uten at kuben nodvendigvis er trang.', 'Dette er ofte et overgangsnivaa der kubeutviklingen kan vippe bade mot sterk produksjonskube eller stagnasjon.', '["Jevn oppbygging", "Normal var eller sommerutvikling", "Kuben har forelopig balansert kapasitet"]', '["Sjekk om plassen fortsatt er tilstrekkelig", "Vurder skattekasse ved okende yngel og trekk", "Se etter om veksten holder seg jevn"]', 'low', 'beginner', 'all', '["inspection", "bistyrke", "kapasitet"]', 7),
      ('bistyrke_7_8', 'Bistyrke 7 til 8 rammer', 'Sterk bistyrke gir god produksjonskapasitet og okt behov for plassstyring.', 'Nar mange rammer er i bruk, blir vurdering av skattekasse, svermetegn og avlegger mer relevant.', '["Sterk utvikling", "God dronning og god ressursbase", "Kuben naermer seg hoy kapasitet"]', '["Vurder skattekasse eller ekstra plass", "Hold oye med svermetegn", "Vurder avlegger hvis andre forhold tilsier det"]', 'medium', 'beginner', 'all', '["inspection", "bistyrke", "kapasitet"]', 3),
      ('bistyrke_9_plus', 'Bistyrke 9 eller flere rammer', 'Svaert sterk bistyrke krever aktiv vurdering av plass, svermetrang og arbeidsbelastning.', 'Store kuber kan produsere godt, men mister ogsa lett kontroll hvis de blir trange eller far ubalanse i plass og trekk.', '["Kraftig utvikling i god sesong", "Sterk dronning og mye yngel", "Kuben har bygd opp stor bemanning"]', '["Prioriter plass og svermforebygging", "Vurder avlegger eller andre kapasitetsgrep", "Folg opp raskt i aktiv sesong"]', 'medium', 'beginner', 'all', '["inspection", "bistyrke", "kapasitet"]', 3),
      ('for_tomt', 'Tomt for for', 'Tom forstatus er kritisk og ma folges opp umiddelbart.', 'Tom kube kan sulte raskt, spesielt i kjolig vaer eller nar yngelproduksjonen er hoy. Host, var og trekkstopp oker risikoen ytterligere.', '["Langvarig trekkmangel", "For liten reserve inn i kulde eller uvaer", "Sterk kube har brukt opp lagrene raskere enn forventet"]', '["Gi akutt stotteforing hvis forholdene tillater det", "Kontroller om kuben fortsatt har ressurser til a komme seg", "Planlegg ny kontroll senest neste dag"]', 'high', 'beginner', 'all', '["inspection", "for", "sesong"]', 1),
      ('for_lite', 'Lite for', 'Lite for krever rask vurdering av trekk, vaer og kubens forbruk.', 'Lav forstatus er ofte handterbar tidlig, men blir raskt mer alvorlig i host, under trekkpauser eller i sterke kuber med mye yngel.', '["Svakt trekk eller darlig vaer", "Sterk kube bruker opp reservene raskt", "Oppfolging kom for sent etter forrige inspeksjon"]', '["Vurder stotteforing", "Kontroller trekkforhold og forbruk", "Sjekk igjen innen fa dager"]', 'high', 'beginner', 'all', '["inspection", "for", "sesong"]', 3),
      ('for_middels', 'Middels forreserve', 'Middels for er ofte tilstrekkelig akkurat na, men ma vurderes ut fra sesong og utvikling.', 'Denne statusen er vanlig i kuber som fortsatt klarer seg selv, men som trenger oppfolging dersom vaeret snur eller yngelmengden oker.', '["Normal bruk av reserver", "Trekken dekker bare deler av behovet", "Kuben er i overgang mellom trekkperioder"]', '["Hold vanlig oppfolging", "Vurder stotte hvis vaeret blir darligere", "Se forstatus sammen med yngel og bistyrke"]', 'low', 'beginner', 'all', '["inspection", "for", "sesong"]', 7),
      ('for_godt', 'God forreserve', 'God forreserve gir kuben trygg buffer for vanlig drift.', 'God reserve betyr ikke at videre oppfolging kan slippes helt. Sterk vekst, darlig vaer eller sen sesong kan likevel spise raskt av lagrene.', '["Kuben har samlet godt", "Tidligere foring har hatt effekt", "Forbruk og tilgang er i balanse"]', '["Fortsett normal oppfolging", "Sjekk at veksten ikke spiser opp bufferen for raskt", "Vurder reservebehov for vaerskifte"]', 'low', 'beginner', 'all', '["inspection", "for", "sesong"]', null),
      ('for_rikelig', 'Rikelig forreserve', 'Rikelig for betyr god buffer og liten akutt risiko for sult.', 'Stor reserve kan vaere svaert gunstig for krevende perioder, men bor fortsatt vurderes sammen med plass, produksjon og sesongplan.', '["God trekk eller nylig foring", "Kuben har bygget stor reserve", "Forbruket er lavere enn tilgangen"]', '["Behold oversikt over reserveutviklingen", "Bruk funnet i planlegging mot host og vinter", "Vurder plass og produksjonsmal videre"]', 'low', 'beginner', 'all', '["inspection", "for", "sesong"]', null),
      ('for_mye', 'Mye for registrert', 'Appverdien mye tilsvarer at kuben har god til rikelig reserve.', 'Denne kompatibilitetsartikkelen brukes der inspeksjonssystemet lagrer verdien mye. Tolk den i praksis som god eller rikelig reserve avhengig av sesong og bistyrke.', '["Kuben har god reserve", "Tidligere foring eller godt trekk", "Forbruket er lavere enn tilgangen"]', '["Tolk funnet sammen med sesong og yngelmengde", "Bruk reservebildet i videre planlegging", "Ingen akutt handling trengs uten andre funn"]', 'low', 'beginner', 'all', '["inspection", "for", "kompatibilitet"]', null),
      ('rolig', 'Rolig gemytt', 'Rolig kube er lett a lese og arbeide i.', 'Rolig gemytt er ofte et godt tegn pa stabil dronning, gode arbeidsforhold og lite stress i kuben.', '["God dronning og stabile forhold", "Skansom inspeksjon", "Lite ytre stress eller rovepress"]', '["Bruk situasjonen til grundig inspeksjon", "Noter som referanse for senere sammenligning", "Fortsett normal oppfolging"]', 'low', 'beginner', 'all', '["inspection", "gemytt"]', null),
      ('normalt', 'Normalt gemytt', 'Normalt gemytt betyr at kuben reagerer forventet uten a vaere spesielt urolig.', 'Normalt gemytt kan variere med vaer, trekk og handtering. Tolkes best over tid og ikke fra en enkelt apning.', '["Vanlig reaksjon pa apning", "Moderate vaer eller trekkforhold", "Ingen tydelige tegn til stress eller dronningproblem"]', '["Se utviklingen over flere inspeksjoner", "Sammenhold med vaer og dronningstatus", "Ingen tiltak alene"]', 'low', 'beginner', 'all', '["inspection", "gemytt"]', null),
      ('urolig', 'Urolig gemytt', 'Urolig kube bor vurderes i sammenheng med vaer, roving, dronning og inspeksjonsbelastning.', 'Uro kan vaere midlertidig, men gjentatt uro kan varsle dronningproblem, stress eller genetikk som bor folges opp.', '["Vaerskifte eller darlig trekk", "Rovepress eller forstyrrelse", "Dronningproblem eller stress i kuben"]', '["Noter om uroen er gjentakende", "Sjekk dronningstatus og forforhold", "Unnga a konkludere etter en vanskelig inspeksjon"]', 'medium', 'beginner', 'all', '["inspection", "gemytt", "kompatibilitet"]', 7),
      ('aggressivt', 'Aggressivt gemytt', 'Aggressiv kube krever ekstra sikkerhet og grundig vurdering av arsak.', 'Aggressivitet kan skyldes genetikk, dronningsvikt, roving eller stress. Dette bor ikke bare noteres, men forstas biologisk.', '["Dronningproblem", "Genetikk", "Roving eller sterk ytre forstyrrelse"]', '["Bruk god beskyttelse og jobb rolig", "Sjekk om aggresjonen er ny eller vedvarende", "Vurder dronningbytte hvis monsteret fortsetter"]', 'medium', 'beginner', 'all', '["inspection", "gemytt"]', 7),
      ('aggressiv', 'Aggressiv kube registrert', 'Appverdien aggressiv tilsvarer aggressivt gemytt som krever oppfolging.', 'Denne kompatibilitetsartikkelen brukes der inspeksjonssystemet lagrer aggressiv. Tolk den som tydelig avvik fra rolig eller normalt gemytt.', '["Dronningproblem", "Genetikk", "Roving eller stress"]', '["Sjekk om problemet gjentar seg", "Vurder arsaker for du griper inn", "Planlegg trygg ny inspeksjon"]', 'medium', 'beginner', 'all', '["inspection", "gemytt", "kompatibilitet"]', 7),
      ('svaert_aggressivt', 'Svaert aggressivt gemytt', 'Svaert aggressiv kube er et hoyrisikofunn og bor tas pa alvor.', 'Nar kuben reagerer voldsomt, bor arsaken avklares raskt. Dette kan pavirke sikkerhet, arbeidsmiljo og videre drift.', '["Alvorlig dronningproblem", "Sterk genetisk defensivitet", "Massivt stress eller roving"]', '["Prioriter sikkerhet ved neste inngrep", "Vurder dronningbytte eller andre grep nar arsaken er avklart", "Unnga unodig apning for plan er lagt"]', 'high', 'beginner', 'all', '["inspection", "gemytt"]', 3),
      ('gitt_for', 'Gitt for', 'Foring brukes for a stotte kuben nar naturgrunnlaget eller reservene ikke er nok.', 'Foring er et tiltak, ikke en sluttvurdering. Etter foring ma birokteren kontrollere om kuben faktisk responderer og om reservene blir bedre.', '["Lite eller tomt for", "Darlig trekk eller uvaer", "Kuben trenger stotte for a holde utviklingen oppe"]', '["Registrer type for og ny forstatus", "Sjekk igjen innen fa dager", "Vurder om underliggende problem fortsatt er til stede"]', 'high', 'beginner', 'all', '["inspection", "action", "for"]', 3),
      ('behandlet_varroa', 'Behandlet varroa', 'Varroabehandling brukes nar middtrykket ma reduseres for a beskytte kuben.', 'Behandling ma alltid etterfolges av kontroll av effekt, timing og om kuben fortsatt viser tegn til belastning.', '["Pavist eller mistenkt varroa", "Sesongmessig behov for behandling", "Forebygging mot okt middtrykk"]', '["Dokumenter nar og hvordan behandling ble gjort", "Planlegg kontroll eller test etter behandlingen", "Sjekk om symptomer avtar"]', 'medium', 'beginner', 'all', '["inspection", "action", "varroa"]', 7),
      ('satt_pa_skattekasse', 'Satt pa skattekasse', 'Skattekasse settes pa nar kuben trenger mer plass til trekk og produksjon.', 'Tiltaket brukes vanligvis i sterke kuber som er pa vei inn i god trekkperiode. Oppfolgingen handler om a sikre nok plass og kontroll pa svermetrang.', '["Kuben er sterk og bygger seg opp", "Trekkforholdene tilsier produksjon", "Plassbehovet i kuben oker"]', '["Kontroller om kassene tas i bruk", "Hold oye med svermetegn", "Vurder videre plassbehov ved neste inspeksjon"]', 'medium', 'beginner', 'all', '["inspection", "action", "produksjon"]', 7),
      ('hostet_honning', 'Hostet honning', 'Honninghosting gjores nar kuben har overskudd som kan tas ut uten a svekke bifolket.', 'Etter honninguttak ma man kontrollere at kuben fortsatt har tilstrekkelige reserver og riktig plass til videre drift.', '["Kuben har produsert overskudd", "Trekkperioden har gitt uttak", "Birokteren folger planlagt produksjonslop"]', '["Vurder forstatus etter uttak", "Sjekk om flere kasser eller rammer ma handteres", "Planlegg videre drift ut fra sesong"]', 'medium', 'beginner', 'all', '["inspection", "action", "honning"]', 7),
      ('byttet_dronning', 'Byttet dronning', 'Dronningbytte brukes nar birokteren vil forbedre eller redde kubens videre utvikling.', 'Tiltaket krever oppfolging for a bekrefte aksept, ro og jevn egglegging. Resultatet kommer forst nar ny dronning fungerer stabilt.', '["Svak egglegging eller darlig utvikling", "Aggressivt gemytt", "Behov for nytt genetisk materiale eller bedre driftskvalitet"]', '["Kontroller om ny dronning er akseptert", "Se etter ferske egg ved neste inspeksjon", "Unnga unodvendig forstyrrelse rett etter byttet"]', 'medium', 'beginner', 'all', '["inspection", "action", "dronning"]', 7),
      ('gjennomfort_varroatest', 'Gjennomfort varroatest', 'Varroatest brukes for a male middtrykk og styre riktige tiltak.', 'En gjennomfort test er bare nyttig hvis resultatet tolkes og folges opp. Testen bor brukes til a avgjore om behandling trengs eller om effekten er god nok.', '["Mistanke om varroa", "Rutinekontroll i sesongen", "Behov for a kontrollere effekt etter behandling"]', '["Noter testresultatet tydelig", "Vurder behandling eller ny test ut fra funn", "Sammenhold testresultat med symptomer i kuben"]', 'high', 'beginner', 'all', '["inspection", "action", "varroa"]', 3),
      ('fjernet_skattekasse', 'Fjernet skattekasse', 'Skattekasse fjernes nar trekk, sesong eller produksjonsbehov tilsier mindre plass.', 'Etter fjerning ma man kontrollere at kuben fortsatt har riktig plass og ikke star for trangt eller med feil reservefordeling.', '["Trekkperioden er over", "Kuben trenger mindre volum", "Produksjonsfasen avsluttes eller endres"]', '["Sjekk plassforhold i yngelrommet", "Vurder forstatus etter omdisponering", "Se etter om kuben fortsatt er i balanse"]', 'medium', 'beginner', 'all', '["inspection", "action", "produksjon"]', 7),
      ('fjernet_dronningceller', 'Fjernet dronningceller', 'Dronningceller fjernes ofte som tiltak mot sverming eller ved styring av dronningsituasjonen.', 'Tiltaket ma folges opp fordi nye dronningceller kan komme raskt tilbake dersom drivkraften i kuben fortsatt er til stede.', '["Svermetrang", "Onske om a styre dronningsforlopet", "Kuben har bygget dronningceller av andre biologiske grunner"]', '["Kontroller raskt om nye celler bygges", "Vurder om plassen eller driftsmaten ma justeres", "Sammenhold tiltaket med kubens styrke og egglegging"]', 'high', 'beginner', 'all', '["inspection", "action", "dronning"]', 3),
      ('satt_inn_rammer', 'Satt inn rammer', 'Rammer settes inn for a gi plass, bygge opp kuben eller styre voksarbeid.', 'Tiltaket bor vurderes mot kubens faktiske kapasitet. For mange rammer for tidlig kan kjole ned yngelrommet og svekke utviklingen.', '["Behov for mer plass", "Utvidelse av kube eller produksjon", "Bygging eller fornying av materiell"]', '["Sjekk om biene tar rammene i bruk", "Vurder varme, styrke og plassbalanse", "Folg opp ved neste inspeksjon"]', 'medium', 'beginner', 'all', '["inspection", "action", "rammer"]', 7),
      ('fjernet_rammer', 'Fjernet rammer', 'Rammer fjernes for a justere plass, rydde ut eller handtere materiell.', 'Etter uttak ma birokteren vurdere om kuben fortsatt har riktig plass og god organisering i yngelrom og produksjonsdel.', '["For mye plass i forhold til styrke", "Behov for utskifting eller rydding", "Birokteren vil stramme inn driften"]', '["Kontroller at kuben ikke blir for trang eller ubalansert", "Noter hva som ble tatt ut", "Sammenhold endringen med videre utvikling"]', 'medium', 'beginner', 'all', '["inspection", "action", "rammer"]', 7),
      ('byttet_voks', 'Byttet voks', 'Voks byttes for a fornye materiell og bedre hygiene og driftskvalitet.', 'Voksfornying er viktig pa sikt, men ma gjores i takt med kubens styrke og evne til a bygge nytt og holde varme.', '["Vedlikehold og hygiene", "Gamle eller morke tavler", "Planlagt fornying av materiell"]', '["Folg med pa om biene bygger nytt godt", "Vurder om byttet var passende for kubens styrke", "Planlegg videre voksfornying gradvis"]', 'medium', 'beginner', 'all', '["inspection", "action", "voks"]', 14),
      ('laget_avlegger', 'Laget avlegger', 'Avlegger lages for formering, svermkontroll eller oppbygging av nye kuber.', 'Etter at avlegger er laget ma bade mor kube og avlegger folges opp separat for a sikre god utvikling og riktig dronningsforlop.', '["Sterk kube taler deling", "Birokteren onsker flere enheter", "Tiltak mot svermetrang eller for a utnytte kapasitet"]', '["Kontroller begge enheter ved neste inspeksjon", "Vurder for og dronningstatus i avleggeren", "Pass pa at mor kuben fortsatt har tilstrekkelig styrke"]', 'medium', 'beginner', 'all', '["inspection", "action", "avlegger"]', 7),
      ('delt_kube', 'Delt kube', 'A dele kube er et storre inngrep for a fordele ressurser, dempe trykk eller lage nye enheter.', 'Deling krever tydelig oppfolging fordi begge deler kan utvikle seg raskt og ulikt etter inngrepet.', '["Sterk kube med hoy kapasitet", "Behov for svermkontroll", "Planlagt oppdeling av bifolk"]', '["Kontroller begge deler raskt etter deling", "Folg med pa dronning og egglegging", "Vurder for og bemanning i begge enheter"]', 'medium', 'beginner', 'all', '["inspection", "action", "deling"]', 7),
      ('status_ok', 'Kubestatus OK', 'Kuben beskrives som stabil uten tydelige avvik i denne inspeksjonen.', 'Status OK betyr ikke at alt er perfekt, men at inspeksjonen samlet sett ikke ga grunnlag for sterkere avvik eller problemmerking.', '["Normal utvikling", "Ingen tydelige problemfunn", "Birokteren vurderer kuben som driftssikker na"]', '["Fortsett vanlig oppfolging", "Sammenhold status med konkrete observasjoner", "Bruk som referanse ved senere endringer"]', 'low', 'beginner', 'all', '["inspection", "status"]', null),
      ('status_sterk', 'Kubestatus sterk', 'Sterk kube har god kapasitet, men krever ogsa aktiv styring av plass og svermetrykk.', 'Sterk status bor stottes av bistyrke, yngelmengde og romforhold. Feil balanse kan gi sverming eller ineffektiv drift.', '["Stor bemanning", "God dronning og god tilgang pa ressurser", "Kuben er i aktiv vekst eller produksjon"]', '["Vurder plassbehov og skattekasse", "Hold oye med svermetegn", "Bruk styrken aktivt i videre driftsplan"]', 'medium', 'beginner', 'all', '["inspection", "status"]', 7),
      ('status_svak', 'Kubestatus svak', 'Svak kube trenger tett vurdering av arsak og utviklingsretning.', 'Svak status kan skyldes alt fra liten avlegger til reelt problem med dronning, sykdom, for eller tap av bier.', '["Liten bemanning", "Dronningproblem eller svak egglegging", "Forpress, sykdom eller darlig vaer over tid"]', '["Vurder hva som er hovedarsaken", "Sjekk for, egg og bistyrke samlet", "Folg opp raskere enn normal rytme"]', 'high', 'beginner', 'all', '["inspection", "status"]', 3),
      ('status_syk', 'Kubestatus syk', 'Kuben vurderes som syk og ma folges opp raskt med smittevern og dokumentasjon.', 'Nar status syk brukes, bor birokteren vaere presis pa hvilke tegn som er sett og om materiell eller bier kan utgjore smitterisiko.', '["Tydelige sykdomstegn", "Svekking hos yngel eller voksne bier", "Mistanke om smittsom eller alvorlig tilstand"]', '["Dokumenter tydelig med notater og bilder", "Unnga unodig flytting av materiell", "Folg opp raskt og vurder smitteverntiltak"]', 'high', 'beginner', 'all', '["inspection", "status"]', 1),
      ('status_dod', 'Kubestatus dod', 'Dod kube betyr at bifolket er tapt eller vurderes uten livskraft.', 'Denne statusen bor brukes med sikker vurdering. Eventuelle rester av yngel, bier eller mat kan fortsatt gi viktig informasjon om hva som skjedde.', '["Sult, sykdom eller stort tap av bier", "Kollaps etter vinter eller belastning", "Alvorlig dronning eller varroaproblem"]', '["Dokumenter funn for rydding", "Vurder smittevern og arsaksanalyse", "Planlegg sikker handtering av materiell"]', 'high', 'beginner', 'all', '["inspection", "status"]', 1),
      ('mottatt_for', 'Mottatt for', 'Kuben har nylig fatt for og bor vurderes etter effekt, ikke bare etter tiltaket i seg selv.', 'Mottatt for sier at et tiltak er gjort, men den biologiske oppfolgingen handler om om kuben faktisk bedrer status og bygger reserve.', '["Birokteren har stottet kuben etter lav reserve", "Trekkforholdene var for svake", "Kuben trengte hjelp i overgang eller darlig vaer"]', '["Sjekk om forstatus faktisk er bedre", "Noter tidspunkt og eventuell type for", "Folg opp innen fa dager hvis kuben fortsatt virker presset"]', 'medium', 'beginner', 'all', '["inspection", "hendelse", "for"]', 3),
      ('skiftet_rammer', 'Rammer er skiftet', 'Rammene er skiftet og kuben bor folges opp for a sikre god organisering og bruk.', 'Skifte av rammer pavirker bade plass, varme og arbeidsflyt i kuben. Folg opp at biene tar losningene i bruk som onsket.', '["Vedlikehold eller opprydding", "Behov for bedre plassfordeling", "Tiltak knyttet til voks eller materiell"]', '["Sjekk at kuben organiserer seg godt etter inngrepet", "Vurder plass og varme ved neste inspeksjon", "Noter hvis endringen pavirket driften positivt eller negativt"]', 'low', 'beginner', 'all', '["inspection", "hendelse", "rammer"]', 7),
      ('sverming', 'Sverming eller tydelig svermpress', 'Sverming eller klart svermpress betyr at kuben kan miste styrke og produksjon raskt.', 'Dette er et problemfunn som ma vurderes ut fra dronningceller, plass, bistyrke og sesong. Jo sterkere kube og jo varmere sesong, desto raskere bor man folge opp.', '["Trang kube", "Sterk utvikling uten nok plass", "Dronningceller og hoy biologisk drivkraft"]', '["Kontroller dronningceller og plassforhold", "Vurder tiltak som avlegger eller mer plass", "Folg opp raskt i aktiv sesong"]', 'high', 'beginner', 'all', '["inspection", "problem"]', 3),
      ('varroa_mistanke', 'Mistanke om varroa', 'Mistanke om varroa bor folges opp med test, dokumentasjon og ny vurdering.', 'Varroa ma forstas ut fra symptomer, sesong og tidligere behandling. Mistanke alene er nok til at oppfolgingen bor vaere strukturert.', '["Okt middtrykk", "Utilstrekkelig effekt av tidligere behandling", "Smittepress fra naerliggende kuber"]', '["Gjennomfor varroatest", "Dokumenter symptomer og bilder ved behov", "Folg opp raskt ut fra resultat og sesong"]', 'high', 'intermediate', 'all', '["inspection", "problem", "varroa"]', 3),
      ('sykdom', 'Sykdom eller tydelige sykdomstegn', 'Sykdom i kube er et alvorlig funn som krever rask og tydelig oppfolging.', 'Sykdom ma vurderes med smittevern i bakhodet. Symptomer hos yngel, bier eller avforing bor dokumenteres og handteres forsiktig.', '["Yngelsykdom eller annen infeksjon", "Virus, parasitter eller svekkelse", "Ukjent biologisk problem som ma avklares"]', '["Dokumenter funn med bilder og presise notater", "Unnga flytting av materiell mellom kuber", "Folg opp umiddelbart eller senest neste dag"]', 'high', 'beginner', 'all', '["inspection", "problem"]', 1),
      ('queen_color_hvit', 'Dronningfarge hvit', 'Hvit dronningmerking hjelper birokteren a identifisere dronningen raskere.', 'Fargeopplysningen er forst og fremst praktisk metadata. Den gjor fremtidige inspeksjoner enklere og reduserer usikkerhet rundt hvilken dronning som er i kuben.', '["Dronningen er merket etter birokterens system", "Dronningen skal vaere lettere a finne", "Kuben folges aktivt over tid"]', '["Kontroller at fargen fortsatt er tydelig", "Bruk fargen som stotte ved senere inspeksjoner", "Sammenhold med argang hvis kjent"]', 'low', 'beginner', 'all', '["inspection", "dronning", "metadata"]', null),
      ('queen_color_gul', 'Dronningfarge gul', 'Gul merking gjor det enklere a identifisere dronningen i inspeksjonen.', 'Fargen er nyttig metadata og bor holdes oppdatert dersom dronningen byttes.', '["Dronningen er merket for enkel identifikasjon", "Birokteren bruker fargesystem pa dronninger", "Kuben folges med historikk over dronning"]', '["Bekreft at merket fortsatt er synlig", "Oppdater registreringen ved dronningbytte", "Bruk fargen som stotte ved kontroll av dronningstatus"]', 'low', 'beginner', 'all', '["inspection", "dronning", "metadata"]', null),
      ('queen_color_rod', 'Dronningfarge rod', 'Rod merking gjor det enklere a folge samme dronning over tid.', 'Fargen er et hjelpemiddel for sporbarhet og praktisk inspeksjon og ikke et biologisk funn i seg selv.', '["Merket dronning for enklere gjenkjenning", "Kuben har kjent dronninghistorikk", "Birokteren bruker systematisk merking"]', '["Noter hvis merket blir borte", "Sammenhold med argang og eventuell byttehistorikk", "Oppdater data ved ny dronning"]', 'low', 'beginner', 'all', '["inspection", "dronning", "metadata"]', null),
      ('queen_color_gronn', 'Dronningfarge gronn', 'Gronn merking gir enklere gjenkjenning av dronningen i videre drift.', 'Metadata om farge hjelper ved raske kontroller og sammenligning mot tidligere inspeksjoner.', '["Birokteren bruker dronningmerking", "Kuben folges systematisk", "Dronningen skal vaere lettere a finne"]', '["Sjekk at markeringen fortsatt stemmer", "Bruk opplysningen i kombinasjon med argang", "Oppdater ved bytte av dronning"]', 'low', 'beginner', 'all', '["inspection", "dronning", "metadata"]', null),
      ('queen_color_bla', 'Dronningfarge bla', 'Bla merking brukes som identifikasjon av dronningen i kuben.', 'Fargen gjor senere inspeksjoner mer effektive og reduserer risiko for feil tolkning av dronningshistorikken.', '["Merket dronning for bedre sporbarhet", "Birokteren har kontroll pa dronningbytter", "Kuben inngar i systematisk oppfolging"]', '["Bekreft at merket fortsatt er korrekt", "Bruk sammen med observasjon av egglegging", "Oppdater registreringen ved ny dronning"]', 'low', 'beginner', 'all', '["inspection", "dronning", "metadata"]', null),
      ('for_type_nodfor', 'Fortype nodfor', 'Nodfor brukes nar kuben trenger rask energi og situasjonen er naer akutt.', 'Nar nodfor brukes, ma oppfolgingen vaere tett fordi behovet ofte peker pa reell forkrise eller rask forverring.', '["Akutt lav forstatus", "Kaldt vaer eller trekkstopp", "Kuben trenger rask stotte for a unnga kollaps"]', '["Kontroller raskt om kuben responderer", "Vurder videre stotteforing hvis nodvendig", "Sjekk igjen senest neste dag eller innen fa dager"]', 'medium', 'beginner', 'all', '["inspection", "for", "metadata"]', 3),
      ('for_type_sukkerlake', 'Fortype sukkerlake', 'Sukkerlake brukes ofte som planlagt stotteforing eller oppbyggingsforing.', 'Tiltaket er mer strukturert enn nodfor, men ma fortsatt folges opp for a sikre at kuben bygger reserve og ikke bare overlever kortsiktig.', '["Planlagt stotteforing", "Trekkmangel eller behov for oppbygging", "Birokteren onsker a styrke reservegrunnlaget"]', '["Kontroller om kuben tar imot foret godt", "Folg med pa reserveutviklingen", "Vurder ny kontroll innen fa dager"]', 'medium', 'beginner', 'all', '["inspection", "for", "metadata"]', 3),
      ('for_type_annet', 'Fortype annet', 'Annen fortype betyr at birokteren har brukt et tiltak som bor beskrives tydelig i notat eller oppfolging.', 'Nar fortype ikke er standardisert, blir dokumentasjon og etterkontroll ekstra viktig for a forsta effekten.', '["Spesialfor eller lokal losning", "Mangel pa standard fortiltak", "Birokteren har valgt tilpasset metode"]', '["Noter hva som faktisk ble brukt", "Vurder effekten ved neste kontroll", "Sammenhold tiltaket med videre forstatus"]', 'medium', 'beginner', 'all', '["inspection", "for", "metadata"]', 3),
      ('rule_eggs_seen_no_sets_egg_unknown', 'Biologisk regel: egg ikke sett betyr usikker eggmengde', 'Nar egg ikke er sett, bor eggmengden ikke tolkes som normal eller hoy uten ekstra forklaring.', 'Dette er en biologisk sikkerhetsregel som hindrer at fravaer av observasjon blir tolket som positiv eggstatus. Felt som motsier hverandre bor bekreftes av birokteren.', '["Motstrid mellom observert og valgt verdi", "Skjemaet ble fylt ut raskt eller i feil rekkefolge", "Birokteren prover a registrere noe som egentlig er usikkert"]', '["Be om bekreftelse for lagring", "Behold eggstatus som usikker inntil ny inspeksjon", "Vis tydelig hvorfor registreringen kan vaere motstridende"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 3),
      ('rule_queen_not_seen_but_eggs_seen', 'Biologisk regel: dronning ikke sett men egg sett', 'Nar egg er sett uten at dronningen er observert, skal systemet forklare at dronningen kan vaere oversett eller nylig ha lagt egg.', 'Regelen skal redusere overreaksjon og samtidig sikre oppfolging. Situasjonen er mulig biologisk, men bor forklares tydelig i Aurora.', '["Dronningen ble oversett", "Eggene er nylig lagt", "Inspeksjonen ga ufullstendig visuell bekreftelse"]', '["Forklar hvorfor situasjonen kan vaere normal", "Anbefal ny inspeksjon innen fa dager", "Unnga a foresla tunge tiltak for mer informasjon foreligger"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 3),
      ('rule_for_lite_host_prioritet_hoy', 'Biologisk regel: lite for om hosten gir hoy prioritet', 'Lite for i hostsesongen skal tolkes strengere enn samme verdi i god trekkperiode.', 'Denne regelen finnes fordi lite reserve sent i sesongen kan fa raskt alvorlige konsekvenser for bade overvintring og kubens generelle styrke.', '["Hoyt sesongbehov og lav sikkerhetsmargin", "Darlig trekk sent i sesongen", "Kuben gar mot vinter med for liten buffer"]', '["Sett hoy prioritet pa oppfolging", "Vurder stotteforing raskt", "Kontroller reserver og vaervindu tett"]', 'high', 'intermediate', 'autumn', '["inspection", "regel", "biologi"]', 1),
      ('rule_dod_med_aktivt_yngel', 'Biologisk regel: dod kube kan ikke samtidig ha aktivt yngelbilde', 'Nar kubestatus er dod, men inspeksjonen samtidig viser aktivt yngelstadium, ma registreringen bekreftes.', 'Regelen skal stoppe biologisk selvmotsigelse i samme inspeksjon og hjelpe birokteren a korrigere feilregistreringer.', '["Feil status ble valgt", "Yngelbildet ble ikke oppdatert", "Inspeksjonen beskriver bade funn for og etter kollaps uten avklaring"]', '["Vis advarsel for lagring", "Be brukeren kontrollere status og yngel", "Forklar hvorfor kombinasjonen er ulogisk"]', 'high', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 1),
      ('rule_sterk_med_lav_bistyrke', 'Biologisk regel: sterk status med lav bistyrke', 'Sterk kube bor normalt ikke kombineres med svaert lavt antall rammer med yngel uten forklaring.', 'Regelen skal hjelpe birokteren a vurdere om sterk betyr total bemanning eller om statusfeltet egentlig bor endres.', '["Status beskriver noe annet enn bistyrke", "Bistyrken ble undervurdert", "Kuben er i overgang og trenger manuell forklaring"]', '["Vis informasjonsvarsel", "Be brukeren bekrefte hva sterk betyr i denne situasjonen", "Vurder om bistyrke eller status bor justeres"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 7),
      ('rule_svak_med_hoy_bistyrke', 'Biologisk regel: svak status med hoy bistyrke', 'Svak kube med mange rammer yngel er ofte et tegn pa at status og styrkemal beskriver ulike ting.', 'Regelen skal ikke stoppe registreringen, men hjelpe med a rydde i biologisk tolkning.', '["Status beskriver gemytt eller annet problem", "Bistyrken er hoyere enn forventet", "Kuben er pa vei opp eller data er blandet"]', '["Vis informasjonsvarsel", "Be brukeren vurdere om statusfeltet er riktig", "Tolke funnet sammen med andre observasjoner"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 7),
      ('rule_for_lite_etter_foring', 'Biologisk regel: fortsatt lite for etter registrert foring', 'Nar foring er registrert samme dag, men forstatus fortsatt er lite, bor systemet sporre om status beskriver for eller etter tiltak.', 'Regelen klargjor tidslinjen i inspeksjonen og reduserer feil tolkning av om tiltaket allerede hadde effekt.', '["Forstatus beskriver funn for tiltak", "Tiltaket har ikke rukket a virke", "Kuben hadde svaert lite reserve for foring"]', '["Be om bekreftelse pa hva statusfeltet beskriver", "Oppmuntre til tydelig notat om tidsrekkefolge", "Folg opp forstatus ved neste kontroll"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 3),
      ('rule_varroa_med_deformerte_vinger', 'Biologisk regel: deformerte vinger oker mistanke om varroa og DWV', 'Nar deformerte vinger observeres, bor Aurora lofte varroa og DWV som sannsynlige forklaringer.', 'Regelen gjor at notatanalyse og sykdomsvurdering henger bedre sammen med kjent biologisk sammenheng.', '["DWV assosiert med hoyt varroatrykk", "Okende middbelastning i kuben", "Svekket bifolk med viruspress"]', '["Anbefal varroatest", "Be om bilder og ny kontroll", "Forklar sammenhengen tydelig for birokteren"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 3),
      ('rule_sverming_ved_sterk_kube', 'Biologisk regel: sterk kube med mye yngel og plassmangel oker svermrisiko', 'Sterk kube med hoy utvikling skal trigge vurdering av sverming, plass og kapasitetsgrep.', 'Regelen er ment a lofte klassiske svermsignaler tidligere, saerlig nar flere felt peker i samme retning.', '["Hoy biologisk vekst", "Trang kube eller lite plass", "Dronningceller og okende trykk i kuben"]', '["Vurder skattekasse eller avlegger", "Kontroller dronningceller", "Folg opp raskt i aktiv sesong"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 3),
      ('rule_dronningbytte_med_aktive_egg', 'Biologisk regel: bytt dronning mens egglegging er aktiv', 'Nar dronningbytte er markert samtidig som eggleggingen ser sterk ut, bor Aurora be om en ekstra bekreftelse.', 'Regelen skal ikke stoppe erfarne biroktere, men hindre at et aktivt og velfungerende eggbilde overses ved ren vane eller feilvalg.', '["Tiltaket er planlagt pa forhand", "Status ble valgt ved en feil", "Birokteren onsker bytte av andre grunner enn eggmengde"]', '["Vis forklarende kontrollsporsmal", "Be brukeren bekrefte hensikten med byttet", "Sammenhold status med gemytt og tidligere historikk"]', 'medium', 'intermediate', 'all', '["inspection", "regel", "biologi"]', 7),
